#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long Y;
        scanf("%lld", &Y);
        long long ans = 0;
        for (int A = 1; A * A <= Y; A++) {
            for (int B = 1; B <= 700; B++) {
                if (A * A + B <= Y) {
                    ans++;
                }
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

