code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            long Y = sc.nextLong();
            long ans = 0;
            for (int A = 1; A * A <= Y; A++) {
                for (int B = 1; B <= 700; B++) {
                    if (A * A + B <= Y) {
                        ans++;
                    }
                }
            }
            System.out.println(ans);
        }
    }
}

